external_knowledge:
- "Stand tall like mountains" is a metaphorical expression used to identify the HRRs with the highest total outpatient reimbursements;
- "Landscape of Medicare's outpatient care" refers to the context of Medicare reimbursement for outpatient services;
- "Summits in reimbursement" metaphorically refers to the highest total outpatient reimbursement amounts.

sql:
SELECT age_group, sex, SUM(enrollee_count) AS total_count
FROM medicare_enrollees
GROUP BY age_group, sex;

SELECT year, AVG(total_reimbursement) AS Average_Reimbursement
FROM reimbursements
GROUP BY year;

SELECT hrrs.hrr_label, inpatient_long_stays.inpatient_long_reimbursement, inpatient_long_stays.year
FROM hrrs
INNER JOIN inpatient_long_stays ON hrrs.hrr_id = inpatient_long_stays.hrr_id;

SELECT year, SUM(inpatient_short_reimbursement) AS total_reimbursement
FROM inpatient_short_stays
GROUP BY year;

SELECT SUM(part_b_professional_reimbursement) AS total_professional_reimbursement
FROM part_b_professional_services
WHERE year = 2020;

SELECT hrrs.hrr_label, reimbursements.total_reimbursement
FROM hrrs
INNER JOIN reimbursements ON hrrs.hrr_id = reimbursements.hrr_id;
